3	import (
4		"fmt"
5		"os"
6		"strings"
7	
8		"github.com/mvwi/wt/internal/git"
9		"github.com/mvwi/wt/internal/github"
10		"github.com/mvwi/wt/internal/tui"
11		"github.com/mvwi/wt/internal/ui"
12		"github.com/spf13/cobra"
13	)
14	
15	var dashCmd = &cobra.Command{
16		Use:     "dash",
17		Aliases: []string{"dashboard"},
18		GroupID: groupWorkflow,
19		Short:   "Live worktree dashboard (TUI)",
20		Long: `Interactive worktree dashboard.
21	
22	Renders the same data as 'wt list' but refreshes periodically and supports
23	keyboard navigation. Press enter on a row to switch to that worktree.
24	
25	For one-shot or scripted output, use 'wt list' instead.`,
26		Example: `  wt dash               Open the live dashboard`,
27		RunE:    runDash,
28	}
29	
30	func init() {
31		rootCmd.AddCommand(dashCmd)
32	}
33	
34	func runDash(cmd *cobra.Command, args []string) error {
35		if !ui.IsTTY() {
36			return fmt.Errorf("wt dash requires a terminal\n   For scripted output, use: wt list --output json")
37		}
38	
39		ctx, err := newContext()
40		if err != nil {
41			return err
42		}
43	
44		cwd, err := os.Getwd()
45		if err != nil {
46			return fmt.Errorf("cannot determine current directory: %w", err)
47		}
48	
49		// Initial load — show a spinner while we collect the slow PR data so the
50		// TUI starts up with a fully populated table.
51		spin := ui.NewSpinner("Loading dashboard")
52		initial, err := gatherDashItems(ctx, cwd)
53		spin.Stop()
54		if err != nil {
55			return err
56		}
57	
58		gather := func() ([]tui.DashItem, error) {
59			// On each tick, re-read cwd in case the user switched in another shell.
60			// We don't update the closure's cwd value because IsCurrent is a UX hint,
61			// not a correctness requirement.
62			return gatherDashItems(ctx, cwd)
63		}
64	
65		closeFn := func(path, branch string) error {
66			// RemoveWorktree passes --force, so dirty/unpushed worktrees are
67			// removable from here. The dashboard already gates risky closes behind
68			// a confirmation prompt — by the time we get here, the user agreed.
69			if err := git.RemoveWorktree(path); err != nil {
70				return err
71			}
72			if branch != "" && git.BranchExists(branch) {
73				_ = git.DeleteBranch(branch)
74			}
75			return nil
76		}
77	
78		fetchDetail := func(item tui.DashItem) (tui.DashDetail, error) {
79			return gatherDashDetail(ctx, item)
80		}
81	
82		rebase := func(path, branch string) (int, error) {
83			return dashRebase(ctx, path)
84		}
85	
86		result, err := tui.RunDashboard(tui.DashConfig{
87			Initial:           initial,
88			Gather:            gather,
89			Close:             closeFn,
90			FetchDetail:       fetchDetail,
91			FetchCommitDetail: gatherCommitDetail,
92			Rebase:            rebase,
93		})
94		if err != nil {
95			return err
96		}
97	
98		if result.SwitchTo != "" && result.SwitchTo != cwd {
99			savePreviousWorktree(cwd)
100			ui.PrintCdHint(result.SwitchTo)
101			short := ctx.shortName(result.SwitchTo)
102			fmt.Printf("%s %s\n", ui.Yellow(ui.Current), short)
103		}
104	
105		return nil
106	}
107	
108	// gatherDashDetail produces the bottom-panel detail for one worktree.
109	// Skips PR lookup when the row has no associated PR. All errors from
110	// individual git/gh calls are tolerated — the partial result is still useful.
111	func gatherDashDetail(ctx *cmdContext, item tui.DashItem) (tui.DashDetail, error) {
112		var d tui.DashDetail
113	
114		if item.IsBase {
115			return d, nil
116		}
117	
118		base := ctx.baseRef()
119	
120		// Recent commits (best-effort)
121		if entries, err := git.LogOnelineIn(item.Path, base, 5); err == nil {
122			for _, e := range entries {
123				d.Commits = append(d.Commits, tui.DashCommit{
124					Hash:    e.Hash,
125					Subject: e.Subject,
126					Age:     e.Age,
127				})
128			}
129		}
130	
131		// Diff stats (best-effort)
132		if stats, err := git.DiffStatsIn(item.Path, base); err == nil {
133			d.Stats = tui.DashDiffStats{
134				Commits:   stats.Commits,
135				Files:     stats.Files,
136				Additions: stats.Additions,
137				Deletions: stats.Deletions,
138			}
139		}
140	
141		// File-by-file changes (best-effort)
142		if files, err := git.DiffFilesIn(item.Path, base); err == nil {
143			for _, f := range files {
144				d.Files = append(d.Files, tui.DashFileChange{Status: f.Status, Path: f.Path})
145			}
146		}
147	
148		// PR detail — title/author/body + named CI checks come from one gh call.
149		if item.PR != nil && github.IsAvailable() {
150			if pr, err := github.GetPRDetail(item.PR.Number); err == nil && pr != nil {
151				d.PRTitle = pr.Title
152				d.PRAuthor = pr.Author.Login
153				d.PRBody = firstParagraph(pr.Body)
154				if item.PR.State == "open" {
155					for _, c := range pr.StatusChecks {
156						if c.Name == "" {
157							continue
158						}
159						d.Checks = append(d.Checks, tui.DashCheck{Name: c.Name, State: c.Result()})
160					}
161				}
162			}
163		}
164	
165		return d, nil
166	}
167	
168	// dashRebase rebases a worktree onto the configured base branch. Async-safe
169	// for use from the dashboard's tea.Cmd: never prompts, never auto-stashes,
170	// aborts cleanly on conflict. Returns the number of commits rebased and an
171	// error describing why the rebase didn't proceed (dirty, conflicts, etc.).
172	func dashRebase(ctx *cmdContext, path string) (int, error) {
173		if git.HasChangesIn(path) {
174			return 0, fmt.Errorf("uncommitted changes")
175		}
176		// Fetch the base ref so the rebase target is current. Failure here is
177		// non-fatal — fall through to rebase against whatever's local.
178		_ = git.Fetch(ctx.Config.Remote, ctx.Config.BaseBranch)
179	
180		ab, err := git.GetAheadBehindIn(path, ctx.baseRef())
181		if err != nil {
182			return 0, err
183		}
184		if ab.Behind == 0 {
185			return 0, nil // up to date
186		}
187		if err := git.RebaseIn(path, ctx.baseRef()); err != nil {
188			git.RebaseAbortIn(path)
189			return 0, fmt.Errorf("conflicts — wt rebase --continue")
190		}
191		return ab.Behind, nil
192	}
193	
194	// gatherCommitDetail loads full metadata + files for one commit. Wraps
195	// git.CommitDetailIn and adapts the result into TUI-layer types.
196	func gatherCommitDetail(worktreePath, hash string) (tui.DashCommitDetail, error) {
197		raw, err := git.CommitDetailIn(worktreePath, hash)
198		if err != nil {
199			return tui.DashCommitDetail{}, err
200		}
201		d := tui.DashCommitDetail{
202			Hash:    raw.Hash,
203			Author:  raw.Author,
204			Date:    raw.Date,
205			Subject: raw.Subject,
206			Body:    raw.Body,
207		}
208		for _, f := range raw.Files {
209			d.Files = append(d.Files, tui.DashCommitFile{
210				Status: f.Status,
211				Path:   f.Path,
212				Adds:   f.Adds,
213				Dels:   f.Dels,
214			})
215		}
216		return d, nil
217	}
218	
219	// firstParagraph returns the first content paragraph of a PR body, skipping
220	// leading markdown headers ("## Summary" etc.). Many PR templates start with a
221	// "## Summary" heading followed by the actual content — we want the content,
222	// not the heading.
223	//
224	// Returns "" if the body is empty or only contains headings.
225	func firstParagraph(body string) string {
226		for {
227			body = strings.TrimSpace(body)
228			if body == "" {
229				return ""
230			}
231			// Leading line is a markdown header — peel it off and look at what
232			// follows. Loop to handle stacked headers like "## Summary\n### Subsection".
233			if strings.HasPrefix(body, "#") {
234				nl := strings.IndexByte(body, '\n')
235				if nl < 0 {
236					return ""
237				}
238				body = body[nl+1:]
239				continue
240			}
241			break
242		}
243		if idx := strings.Index(body, "\n\n"); idx >= 0 {
244			body = body[:idx]
245		}
246		return strings.TrimSpace(body)
247	}
248	
249	// gatherDashItems collects worktree + PR data and converts to TUI items.
250	// Reuses the existing list helpers so dash and list stay in sync.
251	func gatherDashItems(ctx *cmdContext, cwd string) ([]tui.DashItem, error) {
252		worktrees, err := git.ListWorktrees()
253		if err != nil {
254			return nil, err
255		}
256	
257		infos, _ := collectWorktreeInfos(ctx, cwd, worktrees)
258	
259		var openPRs, mergedPRs, closedPRs []github.PR
260		if github.IsAvailable() {
261			openPRs, mergedPRs, closedPRs, _ = fetchPRData()
262		}
263	
264		staleThreshold := ctx.Config.EffectiveStaleThreshold()
265	
266		items := make([]tui.DashItem, 0, len(infos))
267		for _, info := range infos {
268			isBase := ctx.isBaseBranch(info.Branch)
269	
270			item := tui.DashItem{
271				Path:       info.Path,
272				ShortName:  info.ShortName,
273				Branch:     info.Branch,
274				IsCurrent:  info.IsCurrent,
275				IsBase:     isBase,
276				Age:        info.Age,
277				Behind:     info.Behind,
278				Ahead:      info.Ahead,
279				DirtyCount: info.DirtyCount,
280			}
281	
282			if !isBase {
283				openPR := github.FindPRForBranch(openPRs, info.Branch)
284				mergedPR := github.FindPRForBranch(mergedPRs, info.Branch)
285				closedPR := github.FindPRForBranch(closedPRs, info.Branch)
286	
287				daysAgo := git.LastCommitDaysAgo(info.Path)
288				item.StaleDimmed = daysAgo >= staleThreshold && openPR == nil
289	
290				// Unpushed commits are the canonical data-loss signal for close —
291				// fetch for every non-base worktree, not just ones with an open PR.
292				// Cheap call (single rev-list --count); returns 0 if there's no
293				// upstream so no need to special-case.
294				item.Unpushed = git.UnpushedCountIn(info.Path)
295	
296				switch {
297				case openPR != nil:
298					rs := openPR.GetReviewSummary()
299					cs := openPR.GetCISummary()
300					item.PR = &tui.DashPR{
301						Number: openPR.Number,
302						State:  "open",
303						Review: tui.DashReview{Approved: rs.Approved, Changes: rs.Changes, Pending: rs.Pending},
304						CI:     tui.DashCI{Pass: cs.Pass, Fail: cs.Fail, Pending: cs.Pending, Total: cs.Total},
305					}
306				case mergedPR != nil:
