1	package cmd
2	
3	import (
4		"fmt"
5		"os"
6		"slices"
7		"strings"
8	
9		"github.com/mvwi/wt/internal/git"
10		"github.com/mvwi/wt/internal/ui"
11		"github.com/spf13/cobra"
12	)
13	
14	var rebaseCmd = &cobra.Command{
15		Use:     "rebase",
16		GroupID: groupSync,
17		Short:   "Rebase current branch onto base branch (local only)",
18		Long: `Rebase the current branch onto the configured base branch.
19	
20	For feature branches: stash → fetch → rebase → restore stash.
21	For base/main branches: fast-forward merge only.
22	
23	Use --all to rebase all worktrees at once.`,
24		Example: `  wt rebase               Rebase current branch onto base branch
25	  wt rebase --all          Rebase all worktrees at once
26	  wt rebase --continue     Resume after resolving conflicts
27	  wt rebase --abort        Abort rebase and restore state`,
28		RunE: runRebase,
29	}
30	
31	var (
32		rebaseContinueFlag bool
33		rebaseAbortFlag    bool
34		rebaseAllFlag      bool
35	)
36	
37	func init() {
38		rebaseCmd.Flags().BoolVar(&rebaseContinueFlag, "continue", false, "resume after resolving conflicts")
39		rebaseCmd.Flags().BoolVar(&rebaseAbortFlag, "abort", false, "abort rebase and restore state")
40		rebaseCmd.Flags().BoolVarP(&rebaseAllFlag, "all", "a", false, "rebase all worktrees")
41		rootCmd.AddCommand(rebaseCmd)
42	}
43	
44	const stateFileName = "wt-rebase-state"
45	
46	type rebaseOpts struct {
47		continueRebase bool
48		abort          bool
49		all            bool
50	}
51	
52	func runRebase(cmd *cobra.Command, args []string) error {
53		return runRebaseWith(rebaseOpts{
54			continueRebase: rebaseContinueFlag,
55			abort:          rebaseAbortFlag,
56			all:            rebaseAllFlag,
57		})
58	}
59	
60	func runRebaseWith(opts rebaseOpts) error {
61		ctx, err := newContext()
62		if err != nil {
63			return err
64		}
65	
66		if opts.all && (opts.continueRebase || opts.abort) {
67			return fmt.Errorf("--all cannot be combined with --continue or --abort")
68		}
69	
70		if opts.all {
71			return rebaseAll(ctx)
72		}
73	
74		branch, err := git.CurrentBranch()
75		if err != nil {
76			return fmt.Errorf("not in a git repository or detached HEAD\n   Run this from inside a worktree")
77		}
78	
79		if opts.continueRebase {
80			return rebaseContinue(ctx)
81		}
82		if opts.abort {
83			return rebaseAbort()
84		}
85	
86		// Base branch: fast-forward
87		if ctx.isBaseBranch(branch) {
88			return rebaseBaseBranch(ctx, branch)
89		}
90	
91		return rebaseFeatureBranch(ctx, branch)
92	}
93	
94	func rebaseFeatureBranch(ctx *cmdContext, branch string) error {
95		inProgress, _ := git.IsRebaseInProgress()
96		if inProgress {
97			return fmt.Errorf("rebase already in progress\n   Resolve conflicts and run: wt rebase --continue\n   Or abort with: wt rebase --abort")
98		}
99	
100		preRef, _ := git.RevParseHead()
101	
102		fmt.Printf("Syncing branch: %s\n\n", branch)
103	
104		// Stash uncommitted changes
105		didStash := false
106		if git.HasChanges() {
107			fmt.Println("Stashing uncommitted changes...")
108			if err := git.StashPush("wt rebase: auto-stash"); err != nil {
109				return fmt.Errorf("failed to stash changes: %w", err)
110			}
111			didStash = true
112		}
113	
114		// Save state for --continue (format: "stash_state:pre_ref")
115		stashState := "no"
116		if didStash {
117			stashState = "stashed"
118		}
119		_ = git.SaveStateFile(stateFileName, stashState+":"+preRef)
120	
121		// Fetch base branch
122		spin := ui.NewSpinner(fmt.Sprintf("Fetching %s", ctx.baseRef()))
123		if err := git.Fetch(ctx.Config.Remote, ctx.Config.BaseBranch); err != nil {
124			spin.Stop()
125			restoreStash(didStash)
126			git.RemoveStateFile(stateFileName)
127			return fmt.Errorf("failed to fetch from remote: %w", err)
128		}
129	
130		spin.Stop()
131	
132		// Check if up to date
133		ab, err := git.GetAheadBehind(ctx.baseRef())
134		if err == nil && ab.Behind == 0 {
135			restoreStash(didStash)
136			git.RemoveStateFile(stateFileName)
137			ui.Success("Already up to date with %s", ctx.Config.BaseBranch)
138			return nil
139		}
140	
141		// Conflict preview
142		conflicts, conflictErr := git.PotentialConflicts(ctx.baseRef())
143		if conflictErr == nil && len(conflicts) > 0 {
144			fmt.Println()
145			ui.Warn("These files were modified on both branches:")
146			for _, f := range conflicts {
147				fmt.Printf("    %s\n", f)
148			}
149			fmt.Println()
150			if !ui.Confirm("Conflicts are possible. Continue?", true) {
151				restoreStash(didStash)
152				git.RemoveStateFile(stateFileName)
153				fmt.Println("Cancelled")
154				return nil
155			}
156			fmt.Println()
157		}
158	
159		// Rebase
160		fmt.Printf("Rebasing onto %s (%d commit(s) behind)...\n\n", ctx.baseRef(), ab.Behind)
161	
162		if err := git.Rebase(ctx.baseRef()); err != nil {
163			fmt.Println()
164			ui.Warn("Rebase paused due to conflicts")
165			fmt.Println()
166			if didStash {
167				fmt.Println("Your uncommitted changes are stashed and will be restored")
168				fmt.Println("after --continue or --abort.")
169				fmt.Println()
170			}
171			fmt.Println("To resolve:")
172			fmt.Println("  1. Fix the conflicts in the listed files")
173			fmt.Println("  2. Stage the fixes: git add <files>")
174			fmt.Printf("  3. Continue sync: %s\n", ui.Cyan("wt rebase --continue"))
175			fmt.Println()
176			fmt.Printf("Or abort: %s\n", ui.Yellow("wt rebase --abort"))
177			ui.PrintCTA("wt rebase --continue", "wt rebase --abort")
178			return nil // Don't return error — user needs to resolve
179		}
180	
181		restoreStash(didStash)
182		git.RemoveStateFile(stateFileName)
183		autoInstallIfNeeded(ctx, preRef)
184		fmt.Println()
185		ui.Success("Synced with %s", ctx.Config.BaseBranch)
186		return nil
187	}
188	
189	func rebaseBaseBranch(ctx *cmdContext, branch string) error {
190		preRef, _ := git.RevParseHead()
191	
192		fmt.Printf("Syncing %s (fast-forward only)...\n\n", branch)
193	
194		didStash := false
195		if git.HasChanges() {
196			short, _ := git.StatusShort()
197			ui.Warn("You have uncommitted changes:")
198			fmt.Println(short)
199			fmt.Println()
200			if !ui.Confirm("Stash changes and continue?", true) {
201				fmt.Println("Cancelled")
202				return nil
203			}
204			fmt.Println()
205			fmt.Println("Stashing changes...")
206			if err := git.StashPush("wt rebase: auto-stash on " + branch); err != nil {
207				return fmt.Errorf("failed to stash: %w", err)
208			}
209			didStash = true
210			fmt.Println()
211		}
212	
213		// Fetch
214		spin := ui.NewSpinner(fmt.Sprintf("Fetching %s/%s", ctx.Config.Remote, branch))
215		if err := git.Fetch(ctx.Config.Remote, branch); err != nil {
216			spin.Stop()
217			restoreStash(didStash)
218			return fmt.Errorf("failed to fetch from remote: %w", err)
219		}
220	
221		spin.Stop()
222	
223		remoteRef := ctx.Config.Remote + "/" + branch
224		ab, _ := git.GetAheadBehind(remoteRef)
225		if ab.Behind == 0 {
226			restoreStash(didStash)
227			ui.Success("Already up to date")
228			return nil
229		}
230	
231		fmt.Printf("Fast-forwarding (%d commit(s) behind)...\n", ab.Behind)
232		if _, err := git.MergeFF(remoteRef); err != nil {
233			restoreStash(didStash)
234			return fmt.Errorf("cannot fast-forward %s: %w", branch, err)
235		}
236	
237		restoreStash(didStash)
238		autoInstallIfNeeded(ctx, preRef)
239		fmt.Println()
240		ui.Success("%s synced!", branch)
241		return nil
242	}
243	
244	func rebaseContinue(ctx *cmdContext) error {
245		if !git.StateFileExists(stateFileName) {
246			return fmt.Errorf("no rebase in progress\n   Start one with: wt rebase")
247		}
248	
249		inProgress, _ := git.IsRebaseInProgress()
250		if inProgress {
251			fmt.Println("Continuing rebase...")
252			if err := git.RebaseContinue(); err != nil {
253				fmt.Println()
254				ui.Warn("Still have conflicts. Resolve them and run:")
255				fmt.Printf("  %s\n", ui.Cyan("wt rebase --continue"))
256				return nil
257			}
258		}
259	
260		didStash, preRef := parseRebaseState()
261		restoreStash(didStash)
262		git.RemoveStateFile(stateFileName)
263	
264		if preRef != "" {
265			autoInstallIfNeeded(ctx, preRef)
266		}
267	
268		fmt.Println()
269		ui.Success("Synced with base branch")
270		return nil
271	}
272	
273	func rebaseAbort() error {
274		inProgress, _ := git.IsRebaseInProgress()
275		hasState := git.StateFileExists(stateFileName)
276	
277		if !inProgress && !hasState {
278			return fmt.Errorf("no rebase in progress\n   Start one with: wt rebase")
279		}
280	
281		if inProgress {
282			if err := git.RebaseAbort(); err != nil {
283				return fmt.Errorf("failed to abort rebase: %w", err)
284			}
285		}
286	
287		if hasState {
288			didStash, _ := parseRebaseState()
289			restoreStash(didStash)
290			git.RemoveStateFile(stateFileName)
291		}
292	
293		ui.Success("Rebase aborted")
294		return nil
295	}
296	
297	func rebaseAll(ctx *cmdContext) error {
298		worktrees, err := git.ListWorktrees()
299		if err != nil {
300			return err
301		}
302	
303		fmt.Println("Rebasing all worktrees onto", ctx.Config.BaseBranch+"...")
304		fmt.Println()
305	
306		spin := ui.NewSpinner(fmt.Sprintf("Fetching %s", ctx.baseRef()))
307		if err := git.Fetch(ctx.Config.Remote, ctx.Config.BaseBranch); err != nil {
308			spin.Stop()
309			ui.Warn("Fetch failed: %v", err)
310		} else {
311			spin.Stop()
312		}
313		fmt.Println()
314	
315		var rebased, skipped, uptodate, failed int
316	
317		for _, wt := range worktrees {
318			branch, _ := git.CurrentBranchIn(wt.Path)
319			if ctx.isBaseBranch(branch) {
320				short := ctx.shortName(wt.Path)
321				fmt.Printf("  %-25s ", short)
322				remoteRef := ctx.Config.Remote + "/" + ctx.Config.BaseBranch
323				ab, err := git.GetAheadBehindIn(wt.Path, remoteRef)
324				if err != nil || ab.Behind == 0 {
325					fmt.Printf("%s\n", ui.Green("✓ up to date"))
326					uptodate++
327				} else {
328					preRef, _ := git.RevParseHeadIn(wt.Path)
329					if err := git.MergeFFIn(wt.Path, remoteRef); err != nil {
330						fmt.Printf("%s\n", ui.Red("✗ fast-forward failed"))
331						failed++
332					} else {
333						msg := fmt.Sprintf("✓ fast-forwarded (%d commits)", ab.Behind)
334						suffix := lockfileChangedSuffix(wt.Path, preRef)
335						fmt.Printf("%s%s\n", ui.Green(msg), suffix)
336						rebased++
337					}
338				}
339				continue
340			}
341	
342			short := ctx.shortName(wt.Path)
343			fmt.Printf("  %-25s ", short)
344	
345			if git.HasChangesIn(wt.Path) {
346				fmt.Printf("%s\n", ui.Yellow("⚠ has uncommitted changes (skipped)"))
347				skipped++
348				continue
349			}
350	
351			ab, err := git.GetAheadBehindIn(wt.Path, ctx.baseRef())
352			if err != nil || ab.Behind == 0 {
353				fmt.Printf("%s\n", ui.Green("✓ up to date"))
354				uptodate++
355				continue
356			}
357	
358			preRef, _ := git.RevParseHeadIn(wt.Path)
